pub const LLM_CALL_PRECOMPILE: Address = address!("0x0000000000000000000000000000000000000802");
AsyncPrecompileMetadata {
    address: LLM_CALL_PRECOMPILE,
    capability_tag: AsyncPrecompileCapabilityTag::Llm,
    settlement: AsyncPrecompileSettlement::ShortSettlement,
    spc_block_verified: true,
    short_settlement_enabled: true,
}

pub fn observe_call(&mut self, target: Address, caller: Address, input: Bytes) {
    if !is_known_async_precompile(target) { return; }
    self.has_async_call = true;
    self.precompile_address = Some(target);
    self.precompile_input = Some(input);
    self.caller_address = Some(caller);
}

if is_spc_block_verified_precompile(request.precompile_address) {
    let executor_public_key = registry.get_executor(&request.executor).filter(|info| info.is_active).map(|info| info.public_key.clone());
    match executor_public_key {
        Some(public_key) => self.verify_signature_direct(&public_key, request).await?,
        None => return Err(VerificationError::InvalidRequest(...)),
    }
} else {
    self.client.verify_single(request).await?
}
